// Time-stamp: <2025-08-26 11:27:18 rytis>
// Made with love by Rytis.
// Adapted after: https://github.com/Milesight-IoT/SensorDecoders/blob/main/ft-series/ft101/ft101-decoder.js
var RAW_VALUE = 0x00;
var b64   = msg.data;
var bytes = base64ToBytes(b64);
var decoded = decodeToJson("{}");
var attributes = decodeToJson("{}");

function u8(idx)           { return (bytes[idx] & 0xFF); }
//function i8(idx)           { var v = u8(idx); return (v > 0x7F) ? v - 256 : v; }
function readUInt16LE(i)   { return (u8(i)) | (u8(i+1) << 8); }
function readInt16LE(i)    { var v = readUInt16LE(i); return (v >= 0x8000) ? v - 0x10000 : v; }
function readUInt32LE(i)   { var v = (u8(i)) | (u8(i+1)<<8) | (u8(i+2)<<16) | (u8(i+3)<<24); return (v >>> 0); }
function readInt32LE(i)    { var u = readUInt32LE(i); return (u > 0x7FFFFFFF) ? (u - 0x100000000) : u; }
function hex2(n)           { var h = (n & 0xFF).toString(16); var t = "0" + h; return  t.substring(t.length() - 2); }
function readHexStringAt(i,len){ var out=[]; var k=0; while(k<len){ out.push(hex2(u8(i+k))); k++; } return out.join(""); }
function readProtocolVersionAt(i){
    var b=u8(i); var major=(b & 0xF0)>>4; var minor=b & 0x0F; return "v"+major+"."+minor;
}
function readHardwareVersionAt(i){
    var major=u8(i); var minor=(u8(i+1) >> 4); return "v"+major+"."+minor;
}
function readFirmwareVersionAt(i){
    var major=u8(i); var minor=u8(i+1); return "v"+major+"."+minor;
}
function readTslVersionAt(i){
    var major=u8(i); var minor=u8(i+1); return "v"+major+"."+minor;
}
function readSerialNumberAt(i,len){ return readHexStringAt(i,len); }
function getValue(map, key){
    if (RAW_VALUE == 0) return key;
    var v = map[key];
    if (v == null) v = "unknown";
    return v;
}
function readLoRaWANClass(t){
    var m = {0:"Class A",1:"Class B",2:"Class C",3:"Class CtoB"};
    return getValue(m, t);
}
function readDeviceStatus(b){
    var m = {1:"on", 0:"off"};
    return getValue(m, b);
}
//function toNumOr(x, dflt) {
//    if (x == null) return dflt;
//    var n = x * 1;
//    if (n != n) return dflt;   // NaN check (NaN != NaN)
//    return (n >= 0) ? Math.floor(n) : Math.ceil(n);
//}
function stringToNumOr(x, dflt) {
    if (x == null) return dflt;
    //var inner = decodeToJson(x);
    var n = decodeToJson(x);
    return java.lang.Integer.parseInt(n);
    //    if (n != n) return dflt;   // NaN check (NaN != NaN)
    //  return (n >= 0) ? Math.floor(n) : Math.ceil(n);
}

var counter = stringToNumOr(metadata.rttc, 0);

if (bytes != null && bytes.size() == 1 && ((bytes[0] & 0xFF) == 0xFF)) {
    //counter = toNumOr(metadata.rttc, 0) + 1;
    //metadata.put("rttc", counter);
    counter = counter + 1;
    decoded.put("rttc", counter);
} else {
    var i = 0;
    //attrs.put("rttc", 0);
    decoded.put("rttc", 0);
    while (i < bytes.size()) {
	var channel_id   = u8(i++);
	var channel_type = u8(i++);

	// IPSO VERSION
	if (channel_id == 0xFF && channel_type == 0x01) {
        //decoded.ipso_version = readProtocolVersionAt(i);
	    attributes.ipso_version = readProtocolVersionAt(i);
	    i += 1;

	    // HARDWARE VERSION
	} else if (channel_id == 0xFF && channel_type == 0x09) {
	    //decoded.hardware_version = readHardwareVersionAt(i);
	    attributes.hardware_version = readHardwareVersionAt(i);
	    i += 2;

	    // FIRMWARE VERSION
	} else if (channel_id == 0xFF && channel_type == 0x0A) {
	    //decoded.firmware_version = readFirmwareVersionAt(i);
	    attributes.firmware_version = readFirmwareVersionAt(i);
	    i += 2;

	    // DEVICE STATUS
	} else if (channel_id == 0xFF && channel_type == 0x0B) {
	    //decoded.device_status = readDeviceStatus(1);
	    attributes.device_status = readDeviceStatus(1);
	    i += 1;

	    // LORAWAN CLASS
	} else if (channel_id == 0xFF && channel_type == 0x0F) {
	    decoded.lorawan_class = readLoRaWANClass(u8(i));
	    i += 1;

	    // PRODUCT SERIAL NUMBER (8 bytes)
	} else if (channel_id == 0xFF && channel_type == 0x16) {
        //decoded.sn = readSerialNumberAt(i, 8);
        attributes.sn = readSerialNumberAt(i, 8);
	    i += 8;

	    // TSL VERSION
	} else if (channel_id == 0xFF && channel_type == 0xFF) {
	    //decoded.tsl_version = readTslVersionAt(i);
	    attributes.tsl_version = readTslVersionAt(i);
	    i += 2;

	    // LOCATION (lon, lat) each int32, 1e6 scale
	} else if (channel_id == 0x03 && channel_type == 0xA1) {
	    decoded.longitude = readInt32LE(i) / 1000000.0;
	    decoded.latitude  = readInt32LE(i + 4) / 1000000.0;
	    i += 8;

	    // SIGNAL STRENGTH (RSSI, SNR) each int16, 0.1 scale
	} else if (channel_id == 0x04 && channel_type == 0xA2) {
	    decoded.rssi = readInt16LE(i) / 10.0;
	    decoded.snr  = readInt16LE(i + 2) / 10.0;
	    i += 4;

	    // SF (spreading factor) – 1 byte
	} else if (channel_id == 0x05 && channel_type == 0xA3) {
	    decoded.sf = u8(i);
	    i += 1;

	    // TX POWER (int16, 0.01 scale)
	} else if (channel_id == 0x06 && channel_type == 0xA4) {
	    decoded.tx_power = readInt16LE(i) / 100.0;
	    i += 2;

	} else {
	    break;
	}
    }

}

if (decoded.rttc == 0 && decoded.latitude != null && decoded.longitude != null) {
    attributes.put("latitude", decoded.latitude);
    attributes.put("longitude", decoded.longitude);
}

if (attributes.size() > 0) {
    decoded.put("attributes", attributes);
}

return { msg: decoded, metadata: metadata, msgType: msgType };

msg = msg.attributes;
msgType = "POST_ATTRIBUTES_REQUEST";
return {msg: msg, metadata: metadata, msgType: msgType};

if (msg.attributes != null) {
    msg.remove("attributes");
}
return {msg: msg, metadata: metadata, msgType: msgType};
